INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('public-health-specialist-moex-00437', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '在一個存活分析中，共追蹤了200名參與者，最長追蹤達10年。在追蹤期間有50人發生了 疾病事件。暴露組的風險率（hazardrate）估計為每人年0.05，未暴露組的風險率估計為每人 年0.02。請問暴露和事件之間的風險比（hazardratio）是多少？', '["0.40", "0.50", "1.00", "2.50"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00438', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '在一項病例對照研究中，以下那項關於對照組的選擇是正確的？', '["對照組應該是具有結果事件的個體", "對照組應該根據人口學特徵與病例組進行配對", "對照組應該從與病例組相同來源的人群中選擇", "對照組的暴露率應低於病例組"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00439', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於干擾偏差（confoundingbias）的那一個陳述是正確的？', '["干擾偏差總是導致高估暴露和結果之間的關聯", "通過統計分析來調整可以完全消除干擾偏差", "干擾偏差發生在研究樣本數過小的情況下", "干擾偏差可能扭曲了暴露和結果之間的真實關聯，然方向不拘"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00440', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '在一項研究中，研究人員調查運動與心血管疾病風險之間的關聯，並探討這種關聯是否受年 齡的影響。他們進行了分層分析以計算不同年齡組的相對風險（relativerisk,RR）。結果如下： 年齡組1（18-35歲）：RR=0.85 年齡組2（36-50歲）：RR=1.10 年齡組3（51-65歲）：RR=1.30 關於年齡對運動和心血管疾病風險關聯的影響，可以得出下列何項結論？', '["年齡沒有調節效應", "此相關在年輕人中較強", "此相關在最年長組中較強", "這種相關在不同年齡組間效應不一致"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00441', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '在一個多元迴歸分析中，探討年齡、性別和血壓之間的關係，發現年齡和性別的交互作用項 在統計上是顯著的。這個結果應該如何解釋？', '["無論性別如何，年齡和血壓之間存在著強烈的相關", "年齡對血壓的影響因性別而異", "性別對血壓的影響與年齡無關", "必須由交互作用項的效應大小來決定此交互作用是否可忽略"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00442', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '在一個觀察性研究中，研究人員使用傾向分數匹配（propensityscorematching）來減少干擾偏 差。關於傾向分數匹配的陳述那一個是正確的？', '["根據相似的暴露量來進行病例和對照組間的配對", "有助於估計暴露和結果變項間的因果效應", "此匹配能保證在暴露組和未暴露組之所有潛在的干擾因素達到完全的平衡", "是在隨機對照試驗中，最適合來控制干擾偏差的有效方法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00443', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '在將流行病學研究的結果轉化為公共衛生政策時，以下那個因素是相對重要會優先考慮的？', '["主政者的個人偏好和價值觀", "政治的可行性和可接受性", "政策的成本效益和資源配置", "研究成果的科學嚴謹性和統計顯著性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00444', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '一項研究調查吸菸與肺癌間的關聯，並探討特定基因的易感受性是否會修飾這種相關性。研 究人員計算了肺癌案例中吸菸者的可歸因於基因易感性的比例（attributableproportion,AP）。 結果如下： 低基因易感性個體中的AP：0.10 高基因易感性個體中的AP：0.30 關於基因易感性對吸菸與肺癌之關係的修飾效應，可以得出以下那個結論？', '["易感性基因並沒有修飾效應", "在低基因易感性族群間的相關性較強", "在高基因易感性族群間的相關性較強", "無法判斷基因易感性組別間對相關的影響是否一樣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00445', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '以下那一項適當的描述了在流行病學政策應用中的「預防原則」（precautionaryprinciple）？', '["應延遲實施政策，直到政策被證明有效時", "在存在不確定或科學證據可能不足的時候，即採取預防措施", "依賴專家意見和共識，作為政策決策的依據", "優先考慮對大多數人有益的政策，即使此情況下會有一些人受到不利的影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00446', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '以下有關疾病篩檢中前導時間偏差（lead-timebias）的陳述那個是正確的？', '["前導時間偏差發生在篩檢的檢驗未能檢測出早期的疾病時", "前導時間偏差會導致對篩檢效益的高估", "前導時間偏差在基於大樣本族群的篩檢計劃中，不是一個問題", "藉由使用高度敏感的篩檢檢驗法，可以有效消除前導時間偏差"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00447', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '檢驗工具的敏感度（sensitivity）越高，勢必有以下何者特點？', '["特異度（specificity）越低", "偽陰性率越低", "陽性預測值越低", "陰性預測值越低"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00448', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '以下關於疾病發生率（incidence）的描述，何者不恰當？', '["研究族群必須是有機會發病（atriskofdisease）的人", "研究族群沒有失去追蹤才可估計累積發生率（cumulativeincidence）", "發生密度的分母是有機會發病的累積人時（person-time）", "發生率維持大於零，盛行率（prevalence）就會逐漸上升"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00449', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某隨機分派試驗探討飲用蔓越莓汁是否降低尿道感染症。在 24 週的介入研究後，研究者發 現，每日飲用蔓越莓汁組的年化（annualized）泌尿道感染發生密度為0.48，飲用安慰劑飲品 組的年化泌尿道感染發生密度為0.75。根據這些資訊，以下推論何者最適合？', '["每日飲用蔓越莓汁3.7年可預防1次泌尿道感染", "蔓越莓汁組發生泌尿道感染的風險是安慰劑組的0.5倍", "每日飲用蔓越莓汁預防泌尿道感染的成效（efficacy）是56%", "每日飲用蔓越莓汁可降低27%的泌尿道感染風險"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00450', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '下列關於測量誤差（measurementerror）與資訊偏差（informationbias）的描述中，何者正確？', '["樣本數小會增加相關性估計值的測量誤差", "「適應症干擾」（confoundingbyindication）是資訊偏差的一種", "錯誤分組會高估因果相關性的估計值", "測量誤差是資訊偏差的充分條件"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00451', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '報載：「過去數十年來，青少年第二型糖尿病的發生率逐年上升」。其實，在下結論之前，必 須確定各年之間的數據在方法學上可比較。以下幾個方法學上的考量，何者在此主題中比較 不重要？', '["歷年的第二型糖尿病檢驗方法與診斷標準是否一致", "各年數據是否有作年齡標準化", "各次調查之間的抽樣方法是否有改變過", "青少年的年齡定義在各次調查之間是否維持一樣"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00452', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某國針對運輸業勞工進行的調查發現，在男性勞工中，工時越長者，身體質量指數越高，販 賣機上購買冷飲與零食的頻率也越高。而在女性勞工中，工時與身體質量指數或在販賣機上 購買冷飲與零食的頻率都無顯著相關。根據以上描述，以下推論何者正確？', '["職業干擾（confounds）工時與身體質量指數的相關性", "性別修飾（modifies）工時與販賣機消費行為頻率的相關性", "勞工的販賣機消費行為中介（mediates）工時與身體質量指數的相關性", "勞工的工時與販賣機消費行為對身體質量指數的影響有協同作用（synergy）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00453', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '英國千禧世代研究指出，青少年輕生意圖（suicidalattempt）與家長失業以及青少年本身的性 傾向有關。該研究以家長沒有失業的異性戀青少年作為對照組，比較以下三組青少年的輕生 意圖相對風險（relativerisk,RR）：家長沒有失業的性少數青少年（RR=2.92）、兩位家長都失 業的異性戀青少年（RR=2.34）、兩位家長都失業的性少數青少年（RR=7.41）。根據以上描述， 暫不論估計值的信賴區間，下列推論何者正確？', '["性少數青少年的輕生意圖是異性戀青少年的2.92倍", "雙親失業的家庭處境會增加青少年輕生意圖2.34倍", "性少數身分跟雙親失業的家庭處境對青少年的輕生意圖可能有協同式（synergistic）交互作 用的影響", "性少數身分跟雙親失業的家庭處境對青少年的輕生意圖可能有拮抗式（antagonistic）交互 作用的影響"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00454', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '藉由測量舒張壓與收縮壓，當二者之一超過標準則診斷為高血壓。這樣的篩檢方法稱為：', '["系列篩檢，可增加篩檢敏感度", "系列篩檢，可提高篩檢特異度", "平行篩檢，可提高篩檢敏感度", "平行篩檢，可提高篩檢特異度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00455', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '在社區中以觀察式研究設計，藉由比較猴痘感染者與一般民眾的減毒天花疫苗接種率，可分 析該疫苗預防猴痘的效果。某研究以英國在2022年七月到十月間的猴痘確診案例中，以自我 認同為男同性戀、雙性戀與男同性性行為者的成年確診案例作為病例組，以下選項中何者比 較適合作為對照組？', '["同地區中已接種該疫苗的全體成年健康族群", "同地區中未接種該疫苗的全體成年健康族群", "同地區中未接種該疫苗的成年男同性戀、雙性戀與男同性性行為者", "同地區中未感染猴痘的成年男同性戀、雙性戀與男同性性行為者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00456', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某衛生單位利用多重管道宣傳一項社區營養服務。該衛生單位想了解那一個宣傳管道能有效 吸引民眾參與此社區營養服務，於是在參與該服務的民眾中進行隨機抽樣，調查參與者曾從 何處得知此健康服務的消息。從所有場次所收集到的966份問卷中，發現48%曾從親友介紹 得知此服務的消息、62%從活動當天里長廣播得知消息、31%從社區傳單與海報得知消息、 15%從相關新聞報導中得知消息（這四個管道選項可以複選）。根據上列數據，以下推論何者 最恰當？', '["四種宣傳策略相比，里長廣播是宣傳效果最高的管道", "里長廣播的宣傳效果是傳單海報的兩倍", "如果可以進一步交叉比對，則可進一步分析各宣傳管道是否有加成效果", "本數據無法直接分析宣傳效果"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00457', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '多致因的慢性病流行病學中，以下判定因果關係的準則中，何者是最難達成的？', '["時序關係", "劑量效應關係", "一致性", "相關性的專一性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
